            return RpccgoResult.success(worker)
        }
    }

    private fun decodeResultPayload(bytes: ByteArray?): RpccgoResult<ByteArray> {
        if (bytes == null) return RpccgoResult.failure("rpccgo: JNI returned null")
        if (bytes.size < 5) return RpccgoResult.failure("rpccgo: JNI returned malformed result")
        val ok = bytes[0].toInt() != 0
        val length = ByteBuffer.wrap(bytes, 1, 4).order(ByteOrder.BIG_ENDIAN).int
        if (length < 0 || length != bytes.size - 5) return RpccgoResult.failure("rpccgo: JNI returned invalid result length")
        val payload = bytes.copyOfRange(5, bytes.size)
        if (!ok) return RpccgoResult.failure(payload.toString(Charsets.UTF_8))
        return RpccgoResult.success(payload)
    }

    private fun <T> decodeResult(bytes: ByteArray?, parser: (ByteArray) -> T): RpccgoResult<T> {
        val payload = decodeResultPayload(bytes)
        if (!payload.ok) return RpccgoResult.failure(payload.error ?: "rpccgo: JNI call failed")
        return try {
            RpccgoResult.success(parser(payload.value ?: ByteArray(0)))
        } catch (e: Exception) {
            RpccgoResult.failure("rpccgo: JNI payload decode failed: ${e.message ?: e::class.java.name}")
        }
    }

    private fun decodeUnitResult(bytes: ByteArray?): RpccgoResult<Unit> =
        decodeResult(bytes) { Unit }

    private fun decodeHandleResult(bytes: ByteArray?): RpccgoResult<Int> {
        val payload = decodeResultPayload(bytes)
        if (!payload.ok) return RpccgoResult.failure(payload.error ?: "rpccgo: stream start failed")
        val value = payload.value ?: ByteArray(0)
        if (value.size != 4) return RpccgoResult.failure("rpccgo: JNI returned invalid stream handle")
        return RpccgoResult.success(ByteBuffer.wrap(value).order(ByteOrder.BIG_ENDIAN).int)
    }
}

